// ======= QUERY FORNITORI DA SUPABASE =======
const input = $input.first().json;
const body = input.body || input;
const brief = body.brief;
const progettoId = body.progetto_id;

if (!brief || !progettoId) {
  return { json: { error: 'brief e progetto_id richiesti' } };
}

// Prepara i parametri di ricerca per Supabase
const citta = (brief.citta || '').toLowerCase();
const pax = brief.numero_partecipanti || 50;
const budget = brief.budget_totale || 0;

// Identifica componenti richieste
const componenti = [];
if (brief.hotel_attivo) componenti.push('hotel');
if (brief.location_attiva) componenti.push('location');
if (brief.catering_attivo) componenti.push('catering');
if (brief.trasporti_attivi) componenti.push('trasporti');
if (brief.entertainment_attivo) componenti.push('entertainment');
if (brief.teambuilding_attivo) componenti.push('teambuilding');

return {
  json: {
    progetto_id: progettoId,
    brief: brief,
    citta: citta,
    pax: pax,
    budget: budget,
    componenti: componenti
  }
};

// ======= GENERA PROMPT PER AI =======
const parseData = $('Parse Input').first().json;
const brief = parseData.brief;
const fornitori = $input.first().json || [];

// Formatta fornitori YEG trovati
let fornitoriText = '';
if (Array.isArray(fornitori) && fornitori.length > 0) {
  fornitoriText = '\n\n--- FORNITORI DATABASE YEG (prioritari) ---';
  fornitori.forEach(f => {
    const det = [];
    if (f.capacita_max) det.push(`Max ${f.capacita_max} pax`);
    if (f.prezzo_min || f.prezzo_max) det.push(`${f.prezzo_min || '?'}-${f.prezzo_max || '?'} EUR ${f.prezzo_unita || ''}`);
    if (f.specifiche) det.push(JSON.stringify(f.specifiche));
    if (f.note) det.push(f.note);
    fornitoriText += `\n[${f.categoria}] ${f.nome} (${f.citta}) | ${det.join(' | ')}`;
  });
  fornitoriText += '\n--- FINE FORNITORI YEG ---';
}

// Costruisci dettagli componenti
let dettagli = '';
if (brief.hotel_attivo) {
  dettagli += `\n\nHOTEL: check-in ${brief.hotel_checkin}, check-out ${brief.hotel_checkout}, ${brief.camere_singole} singole + ${brief.camere_doppie} doppie = ${(brief.camere_singole||0)+(brief.camere_doppie||0)} camere, min ${brief.hotel_stelle_minime || 4} stelle. ${brief.hotel_note || ''}`;
}
if (brief.location_attiva) {
  dettagli += `\n\nLOCATION: setup ${brief.location_setup}, AV: ${(brief.location_av||[]).join(', ')}, tipologia: ${brief.location_tipologia || 'qualsiasi'}. ${brief.location_note || ''}`;
}
if (brief.catering_attivo) {
  dettagli += `\n\nCATERING: ${brief.coffee_break_num || 0} coffee break, ${brief.pranzo_num || 0} pranzi, ${brief.cena_num || 0} cene, ${brief.aperitivo_num || 0} aperitivi. Esigenze: ${brief.esigenze_alimentari || 'nessuna'}. ${brief.catering_note || ''}`;
}
if (brief.trasporti_attivi) {
  dettagli += `\n\nTRASPORTI: ${(brief.trasporti_tipo||[]).join(', ')}. ${brief.trasporti_note || ''}`;
}
if (brief.entertainment_attivo) {
  dettagli += `\n\nENTERTAINMENT: ${brief.entertainment_tipo || 'da definire'}. ${brief.entertainment_note || ''}`;
}
if (brief.teambuilding_attivo) {
  dettagli += `\n\nTEAM BUILDING: ${brief.teambuilding_note || 'da definire'}`;
}

const prompt = `Sei un senior event planner dell'agenzia YEG Events (Torino). Analizza questo brief e genera proposte CONCRETE e REALI.

--- BRIEF ---
Evento: ${brief.nome_evento} (${brief.tipologia_evento})
Azienda: ${brief.azienda}
Citta: ${brief.citta}
Date: ${brief.data_inizio} ${brief.orario_inizio || ''} - ${brief.data_fine} ${brief.orario_fine || ''}
Partecipanti: ${brief.numero_partecipanti}
Budget totale: ${brief.budget_totale || 'da definire'} EUR
Agenda: ${brief.agenda || 'non specificata'}
${dettagli}
--- FINE BRIEF ---
${fornitoriText}

OBIETTIVO: Per OGNI componente richiesta (${parseData.componenti.join(', ')}), genera esattamente 5 proposte.

PRIORITA AI FORNITORI YEG: se ci sono fornitori YEG adatti (capacita, citta, budget), mettili nelle prime posizioni con is_yeg_supplier:true. Completa con fornitori reali trovabili online.

INOLTRE, genera un campo "brief_interpretato" con la tua analisi del brief.

RISPONDI SOLO JSON:
{
  "brief_interpretato": {
    "sintesi": "riepilogo in 2-3 frasi",
    "obiettivi_evento": "cosa vuole ottenere il cliente",
    "tono_evento": "formale|informale|lusso|dinamico",
    "priorita": ["lista priorita"],
    "suggerimenti_ai": "consigli strategici per l'event manager"
  },
  "categorie": {
    "nome_categoria": {
      "proposte": [
        {
          "nome": "Nome reale fornitore",
          "categoria": "location|catering|hotel|trasporti|entertainment|teambuilding",
          "descrizione": "max 80 parole",
          "motivo_match": "perche risolve QUESTA esigenza del brief",
          "prezzo_stimato": numero,
          "capacita": "capienza",
          "indirizzo": "indirizzo/zona",
          "punti_forza": ["p1","p2","p3"],
          "adeguatezza_budget": 0-100,
          "note": "criticita o info extra",
          "sito_web": "URL reale",
          "contatto": "tel/email se noto",
          "is_yeg_supplier": true/false
        }
      ]
    }
  }
}`;

return {
  json: {
    progetto_id: parseData.progetto_id,
    prompt: prompt,
    componenti: parseData.componenti
  }
};

