// ======= SALVA PROPOSTE IN SUPABASE =======
const aiResponse = $input.first().json;
const progettoId = $('Genera Prompt AI').first().json.progetto_id;

// Parsing risposta AI
let parsed;
try {
  const content = aiResponse.choices[0].message.content;
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  const content = aiResponse.choices[0].message.content;
  const m = content.match(/\{[\s\S]*\}/);
  if (m) parsed = JSON.parse(m[0]);
  else throw new Error('JSON non valido dalla AI');
}

// Raccogli tutte le proposte
const proposte = [];
if (parsed.categorie) {
  for (const [catKey, catData] of Object.entries(parsed.categorie)) {
    const prps = catData.proposte || [];
    prps.forEach((p, idx) => {
      proposte.push({
        progetto_id: progettoId,
        categoria: p.categoria || catKey,
        nome: p.nome,
        descrizione: p.descrizione || null,
        motivo_match: p.motivo_match || null,
        prezzo_stimato: p.prezzo_stimato || null,
        capacita: p.capacita || null,
        indirizzo: p.indirizzo || null,
        punti_forza: p.punti_forza || [],
        adeguatezza_budget: p.adeguatezza_budget || null,
        note: p.note || null,
        sito_web: p.sito_web || null,
        contatto: p.contatto || null,
        immagine_url: p.immagine_url || null,
        fonte: 'ai',
        is_yeg_supplier: p.is_yeg_supplier || false,
        selezionato_manager: false,
        selezionato_cliente: false,
        ordine: idx
      });
    });
  }
}

return {
  json: {
    progetto_id: progettoId,
    brief_interpretato: parsed.brief_interpretato || null,
    proposte: proposte,
    totale_proposte: proposte.length
  }
};
